"use client";

import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { Points, PointMaterial, Float, Environment, Center } from "@react-three/drei";
import * as THREE from "three";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { BackgroundShader } from "./BackgroundShader";

gsap.registerPlugin(ScrollTrigger);

// Intelligent Particle Stream
function ParticleStream() {
  const pointsRef = useRef<THREE.Points>(null);
  const count = 5000;
  
  const positions = useMemo(() => {
    const pos = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 20;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 20;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 20;
    }
    return pos;
  }, []);

  useFrame((state, delta) => {
    if (pointsRef.current) {
      pointsRef.current.rotation.y += delta * 0.05;
      pointsRef.current.rotation.x += delta * 0.02;
    }
  });

  return (
    <Points ref={pointsRef} positions={positions} stride={3} frustumCulled={false}>
      <PointMaterial
        transparent
        color="#3b82f6"
        size={0.02}
        sizeAttenuation={true}
        depthWrite={false}
        opacity={0.4}
        blending={THREE.AdditiveBlending}
      />
    </Points>
  );
}

// Neural Core (The Hero Centerpiece)
function NeuralCore() {
  const meshRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (meshRef.current) {
      meshRef.current.rotation.y = state.clock.getElapsedTime() * 0.2;
      meshRef.current.position.y = Math.sin(state.clock.getElapsedTime()) * 0.1;
    }
  });

  return (
    <group ref={meshRef}>
      <Center>
        <mesh>
          <icosahedronGeometry args={[1.5, 15]} />
          <meshStandardMaterial 
            color="#2563eb" 
            wireframe 
            transparent 
            opacity={0.4}
            emissive="#3b82f6"
            emissiveIntensity={2}
          />
        </mesh>
        <mesh scale={[0.8, 0.8, 0.8]}>
          <icosahedronGeometry args={[1.5, 1]} />
          <meshStandardMaterial 
            color="#ffffff" 
            metalness={1} 
            roughness={0} 
            emissive="#ffffff"
            emissiveIntensity={0.5}
          />
        </mesh>
      </Center>
    </group>
  );
}

// Success Constellation (The Achievement Field)
function SuccessConstellation() {
  const pointsRef = useRef<THREE.Points>(null);
  const count = 1000;
  
  const positions = useMemo(() => {
    const pos = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      // Shape it roughly like a galaxy or high-density cluster
      const r = Math.random() * 10;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta) + 20; // Positioned higher up
      pos[i * 3 + 2] = r * Math.cos(phi) - 10;
    }
    return pos;
  }, []);

  useFrame((state, delta) => {
    if (pointsRef.current) {
      pointsRef.current.rotation.y += delta * 0.1;
    }
  });

  return (
    <Points ref={pointsRef} positions={positions} stride={3} frustumCulled={false}>
      <PointMaterial
        transparent
        color="#fbbf24" // Amber/Gold color for success
        size={0.05}
        sizeAttenuation={true}
        depthWrite={false}
        opacity={0.8}
        blending={THREE.AdditiveBlending}
      />
    </Points>
  );
}

// Cinematic Camera Orchestrator
function CameraOrchestrator() {
  const { camera } = useThree();

  useEffect(() => {
    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: ".main-odyssey-wrapper",
        start: "top top",
        end: "bottom bottom",
        scrub: 2,
      }
    });

    // Sequence 1: Zoom into Neural Core
    tl.to(camera.position, { z: 4, y: 0, x: 2, ease: "power2.inOut" });
    
    // Sequence 2: Rise to Success Constellation
    tl.to(camera.position, { z: 10, y: 5, x: -2, ease: "power2.inOut" });
    tl.to(camera.rotation, { x: -0.2, ease: "power2.inOut" }, "<");

    // Sequence 3: Deep plunge into the Foundation
    tl.to(camera.position, { z: -5, y: -2, x: 0, ease: "slow(0.7, 0.7, false)" });

    return () => {
      tl.kill();
    };
  }, [camera]);

  return null;
}

export function Odyssey3D() {
  return (
    <div className="fixed inset-0 w-full h-full z-0">
      <Canvas 
        camera={{ position: [0, 0, 8], fov: 45 }} 
        dpr={[1, 2]}
        gl={{ antialias: true, alpha: true }}
      >
        <color attach="background" args={["#000000"]} />
        <ambientLight intensity={0.5} />
        <pointLight position={[10, 10, 10]} intensity={2} color="#3b82f6" />
        <spotLight position={[-10, 10, 10]} angle={0.15} penumbra={1} intensity={2} />
        
        <BackgroundShader />
        <ParticleStream />
        
        <Float speed={2} rotationIntensity={0.5} floatIntensity={1}>
           <NeuralCore />
        </Float>

        <group position={[0, -20, 0]}>
           <SuccessConstellation />
        </group>

        <Environment preset="city" />
        <CameraOrchestrator />
      </Canvas>
    </div>
  );
}
